-- ============================================================\n-- UNIFIED ENTERPRISE INTEGRATION — Migration 13: Unify Customers\n-- ============================================================\n\n-- 1. Alter public.customers to add all missing columns from customer_profiles\nALTER TABLE public.customers\n  ADD COLUMN IF NOT EXISTS portal_user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE UNIQUE,\n  ADD COLUMN IF NOT EXISTS company_name TEXT,\n  ADD COLUMN IF NOT EXISTS tax_number TEXT,\n  ADD COLUMN IF NOT EXISTS commercial_register TEXT,\n  ADD COLUMN IF NOT EXISTS contact_email TEXT,\n  ADD COLUMN IF NOT EXISTS contact_phone TEXT,\n  ADD COLUMN IF NOT EXISTS website TEXT,\n  ADD COLUMN IF NOT EXISTS logo_url TEXT,\n  ADD COLUMN IF NOT EXISTS is_verified BOOLEAN DEFAULT FALSE,\n  ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW();\n\n-- 2. Migrate existing profiles from customer_profiles into customers\nINSERT INTO public.customers (\n  portal_user_id, \n  company_name, \n  name, \n  tax_number, \n  commercial_register, \n  contact_email, \n  contact_phone, \n  website, \n  logo_url, \n  is_verified, \n  created_at, \n  updated_at\n)\nSELECT \n  portal_user_id, \n  company_name, \n  company_name, -- using company_name as name fallback\n  tax_number, \n  commercial_register, \n  contact_email, \n  contact_phone, \n  website, \n  logo_url, \n  is_verified, \n  created_at, \n  updated_at\nFROM public.customer_profiles\nON CONFLICT (portal_user_id) DO UPDATE\nSET \n  company_name = EXCLUDED.company_name,\n  tax_number = EXCLUDED.tax_number,\n  commercial_register = EXCLUDED.commercial_register,\n  contact_email = EXCLUDED.contact_email,\n  contact_phone = EXCLUDED.contact_phone,\n  website = EXCLUDED.website,\n  logo_url = EXCLUDED.logo_url,\n  is_verified = EXCLUDED.is_verified,\n  updated_at = EXCLUDED.updated_at;\n\n-- 3. Re-link customer_branches to point to public.customers\nALTER TABLE public.customer_branches \n  DROP CONSTRAINT IF EXISTS customer_branches_customer_id_fkey;\n\n-- Temporarily update customer_branches customer_id by mapping customer_profiles.portal_user_id to customers.id\nUPDATE public.customer_branches b\nSET customer_id = c.id\nFROM public.customer_profiles p\nJOIN public.customers c ON c.portal_user_id = p.portal_user_id\nWHERE b.customer_id = p.id;\n\nALTER TABLE public.customer_branches\n  ADD CONSTRAINT customer_branches_customer_id_fkey \n  FOREIGN KEY (customer_id) REFERENCES public.customers(id) ON DELETE CASCADE;\n\n-- 4. Re-link customer_documents to point to public.customers\nALTER TABLE public.customer_documents\n  DROP CONSTRAINT IF EXISTS customer_documents_customer_id_fkey;\n\nUPDATE public.customer_documents d\nSET customer_id = c.id\nFROM public.customer_profiles p\nJOIN public.customers c ON c.portal_user_id = p.portal_user_id\nWHERE d.customer_id = p.id;\n\nALTER TABLE public.customer_documents\n  ADD CONSTRAINT customer_documents_customer_id_fkey \n  FOREIGN KEY (customer_id) REFERENCES public.customers(id) ON DELETE CASCADE;\n\n-- 5. Re-link customer_wallets to point to public.customers\nALTER TABLE public.customer_wallets\n  DROP CONSTRAINT IF EXISTS customer_wallets_customer_id_fkey;\n\nUPDATE public.customer_wallets w\nSET customer_id = c.id\nFROM public.customer_profiles p\nJOIN public.customers c ON c.portal_user_id = p.portal_user_id\nWHERE w.customer_id = p.id;\n\nALTER TABLE public.customer_wallets\n  ADD CONSTRAINT customer_wallets_customer_id_fkey \n  FOREIGN KEY (customer_id) REFERENCES public.customers(id) ON DELETE CASCADE;\n\n-- 6. Clean up: Drop customer_profiles table\nDROP TABLE IF EXISTS public.customer_profiles CASCADE;\n\n-- 7. Add product approval column safety defaults\nALTER TABLE public.products \n  ALTER COLUMN approval_status SET DEFAULT 'Pending';\n
